// CLX B2C Discovery v2 — Build search query list
// 43 queries × 5 GTA cities = 215 scan combinations

const cities = ['Toronto', 'Mississauga', 'Brampton', 'Vaughan', 'Markham'];

const queries = [
  // Moving services (7)
  { query: 'local moving company',         industry: 'moving services',  product_type: 'moving_services' },
  { query: 'long distance movers',         industry: 'moving services',  product_type: 'moving_services' },
  { query: 'residential movers',           industry: 'moving services',  product_type: 'moving_services' },
  { query: 'apartment movers',             industry: 'moving services',  product_type: 'moving_services' },
  { query: 'piano movers',                 industry: 'moving services',  product_type: 'moving_services' },
  { query: 'furniture movers',             industry: 'moving services',  product_type: 'moving_services' },
  { query: 'moving and storage',           industry: 'moving services',  product_type: 'moving_services' },

  // Insurance (4)
  { query: 'auto insurance broker',        industry: 'insurance',         product_type: 'insurance' },
  { query: 'home insurance broker',        industry: 'insurance',         product_type: 'insurance' },
  { query: 'life insurance agent',         industry: 'insurance',         product_type: 'insurance' },
  { query: 'health insurance broker',      industry: 'insurance',         product_type: 'insurance' },

  // Dental (3)
  { query: 'dentist',                      industry: 'dental',            product_type: 'dental' },
  { query: 'cosmetic dentist',             industry: 'dental',            product_type: 'dental' },
  { query: 'pediatric dentist',            industry: 'dental',            product_type: 'dental' },

  // Hair and beauty (3)
  { query: 'hair salon',                   industry: 'hair and beauty',   product_type: 'beauty' },
  { query: 'beauty salon',                 industry: 'hair and beauty',   product_type: 'beauty' },
  { query: 'nail salon',                   industry: 'hair and beauty',   product_type: 'beauty' },

  // Cleaning services (3)
  { query: 'residential cleaning service', industry: 'cleaning services', product_type: 'cleaning_services' },
  { query: 'house cleaning',               industry: 'cleaning services', product_type: 'cleaning_services' },
  { query: 'maid service',                 industry: 'cleaning services', product_type: 'cleaning_services' },

  // Construction (6)
  { query: 'home renovation contractor',   industry: 'construction',      product_type: 'construction' },
  { query: 'kitchen renovation',           industry: 'construction',      product_type: 'construction' },
  { query: 'bathroom renovation',          industry: 'construction',      product_type: 'construction' },
  { query: 'roofing contractor',           industry: 'construction',      product_type: 'construction' },
  { query: 'landscaping contractor',       industry: 'construction',      product_type: 'construction' },
  { query: 'general contractor',           industry: 'construction',      product_type: 'construction' },

  // Kijiji-style active demand signals (7)
  { query: 'moving help wanted',                     industry: 'moving services',   product_type: 'moving_services' },
  { query: 'last minute movers',                     industry: 'moving services',   product_type: 'moving_services' },
  { query: 'same day moving service',                industry: 'moving services',   product_type: 'moving_services' },
  { query: 'cleaner wanted',                         industry: 'cleaning services', product_type: 'cleaning_services' },
  { query: 'deep cleaning service',                  industry: 'cleaning services', product_type: 'cleaning_services' },
  { query: 'emergency dentist',                      industry: 'dental',            product_type: 'dental' },
  { query: 'walk in dental clinic',                  industry: 'dental',            product_type: 'dental' },

  // New-business insurance signals (4)
  { query: 'commercial insurance broker',            industry: 'insurance',         product_type: 'insurance' },
  { query: 'business liability insurance',           industry: 'insurance',         product_type: 'insurance' },
  { query: 'small business insurance broker',        industry: 'insurance',         product_type: 'insurance' },
  { query: 'key person insurance agent',             industry: 'insurance',         product_type: 'insurance' },

  // Commercial moving signals (3)
  { query: 'office movers',                          industry: 'moving services',   product_type: 'moving_services' },
  { query: 'commercial movers',                      industry: 'moving services',   product_type: 'moving_services' },
  { query: 'business relocation services',           industry: 'moving services',   product_type: 'moving_services' },

  // New-home signals (3)
  { query: 'new home movers',                        industry: 'moving services',   product_type: 'moving_services' },
  { query: 'new homeowner insurance',                industry: 'insurance',         product_type: 'insurance' },
  { query: 'family dentist accepting new patients',  industry: 'dental',            product_type: 'dental' }
];

console.log('[CLX B2C v2] Total queries: ' + queries.length);

const scanList = [];
for (const city of cities) {
  for (const q of queries) {
    scanList.push({
      city: city,
      industry: q.industry,
      product_type: q.product_type,
      search_query: q.query + ' in ' + city + ' Canada'
    });
  }
}

console.log('[CLX B2C v2] Total scan combinations: ' + scanList.length);

return scanList.map(item => ({ json: item }));

// CLX B2C v2 — Handle Maps Error
// Inspects the Search Google Maps response. If the node failed or the body
// carries a Google error, flags the item so IF Maps OK can route to
// Log Maps Error. Otherwise passes through the raw places response.
const ctx = $('Split In Batches').item.json;
const raw = $input.item.json || {};

// continueOnFail leaves an error property on the item when the HTTP call failed
const httpError = raw.error || raw.errorMessage || null;
const statusCode = raw.statusCode || (raw.headers && raw.headers.status) || null;

// Google Places error shape: { error: { code, message, status } }
const body = raw.body || raw;
const googleError = body && body.error && (body.error.message || body.error.status) ? body.error : null;

const httpFailed = (typeof statusCode === 'number' && statusCode >= 400);
const hasError = Boolean(httpError || googleError || httpFailed);

if (hasError) {
  const code = googleError ? String(googleError.code || googleError.status || 'google_error')
             : httpFailed ? String(statusCode)
             : 'unknown';
  const message = googleError ? (googleError.message || googleError.status || 'Google Places error')
                : httpError ? String(httpError)
                : 'HTTP ' + statusCode;
  console.log('[CLX B2C v2] Maps error for "' + ctx.search_query + '": ' + message);
  return {
    json: {
      has_error: true,
      error_code: code,
      error_message: message,
      input_data: ctx,
      ...ctx
    }
  };
}

// Success path — forward the body so Parse Places Results can read `places`
return {
  json: {
    has_error: false,
    ...ctx,
    places: (body && body.places) || []
  }
};

// CLX B2C v2 — Parse Places Results
// Reads the places array forwarded by Handle Maps Error and builds
// a deduped business list for this scan query.
const data = $input.item.json || {};
const ctx = $('Split In Batches').item.json;
const places = Array.isArray(data.places) ? data.places : [];

if (places.length === 0) {
  return { json: { businesses: [], count: 0, results_found: 0, ...ctx } };
}

const businesses = [];
const seen = {};

for (const place of places) {
  const name = (place.displayName && place.displayName.text) ? place.displayName.text : '';
  if (!name) continue;
  const key = name.toLowerCase();
  if (seen[key]) continue;
  seen[key] = true;

  businesses.push({
    name: name,
    formatted_address: place.formattedAddress || '',
    phone: place.nationalPhoneNumber || '',
    website: place.websiteUri || '',
    place_id: place.id || '',
    city: ctx.city,
    industry: ctx.industry,
    product_type: ctx.product_type,
    search_query: ctx.search_query
  });
}

console.log('[CLX B2C v2] Parsed ' + businesses.length + ' businesses for query: ' + ctx.search_query);

return {
  json: {
    businesses: businesses,
    count: businesses.length,
    results_found: businesses.length,
    ...ctx
  }
};

// CLX B2C v2 — Process Each Business
// Emits one item per business, mapped to the Supabase RPC parameter names
// (p_* prefix) for insert_lead_if_not_exists. Uses null (not empty strings)
// for unknown fields so Supabase defaults / RPC logic behave correctly.
const data = $('Parse Places Results').item.json;
const businesses = data.businesses || [];
if (businesses.length === 0) return [];

return businesses.map(biz => ({
  json: {
    p_full_name: null,
    p_email: null,
    p_phone: biz.phone || null,
    p_company: biz.name,
    p_job_title: 'Owner',
    p_industry: biz.industry,
    p_city: biz.city,
    p_source: 'google_maps_discovery',
    p_lead_status: 'New Lead',
    p_product_type: biz.product_type,
    p_notes: 'Places ID: ' + (biz.place_id || '') + ' | Address: ' + (biz.formatted_address || '') + (biz.website ? ' | Website: ' + biz.website : ''),
    _scan_city: biz.city,
    _scan_query: biz.search_query,
    _scan_industry: biz.industry,
    _scan_product_type: biz.product_type
  }
}));

// CLX B2C v2 — Parse RPC Response
// Reads the insert_lead_if_not_exists response. Handles three cases:
//   1. HTTP error (continueOnFail left an error shape) → log to scan_errors, emit duplicate (to loop back)
//   2. status = 'inserted' → forward as inserted
//   3. status = 'duplicate' → forward as duplicate
const input = $input.item.json || {};
const ctx = $('Process Each Business').item.json || {};
const company = ctx.p_company || 'unknown';

// Detect HTTP-layer failure (continueOnFail)
const httpErr = input.error || input.errorMessage || null;
const statusCode = typeof input.statusCode === 'number' ? input.statusCode : null;
const httpFailed = httpErr || (statusCode !== null && statusCode >= 400);

if (httpFailed) {
  const message = httpErr ? String(httpErr) : ('HTTP ' + statusCode);
  console.log('[CLX B2C v2] RPC failure for ' + company + ': ' + message);
  return {
    json: {
      status: 'error',
      error_code: httpErr ? 'rpc_error' : String(statusCode),
      error_message: message,
      company: company,
      _scan_city: ctx._scan_city,
      _scan_query: ctx._scan_query,
      _scan_industry: ctx._scan_industry,
      _scan_product_type: ctx._scan_product_type,
      input_data: ctx
    }
  };
}

// Supabase returns the RPC result in `body`. For a record-returning function
// it comes back as an array; for a composite-returning function it may be an object.
const body = input.body !== undefined ? input.body : input;
let rec = null;
if (Array.isArray(body)) {
  rec = body[0] || null;
} else if (body && typeof body === 'object') {
  rec = body;
}

const status = rec && rec.status ? String(rec.status).toLowerCase() : 'unknown';
const id = rec && rec.id ? rec.id : null;

console.log('[CLX B2C v2] RPC ' + status + ' for ' + company + (id ? ' (id=' + id + ')' : ''));

return {
  json: {
    status: status,
    id: id,
    company: company,
    _scan_city: ctx._scan_city,
    _scan_query: ctx._scan_query,
    _scan_industry: ctx._scan_industry,
    _scan_product_type: ctx._scan_product_type
  }
};

// CLX B2C v2 — Scan Complete Summary
// Aggregates today's scan_log entries and emits a single summary item.
// Connect this to Slack / email / webhook later — for now it is a no-op
// endpoint that prints the totals to the execution log.
const resp = $('Fetch Today Scan Log').item.json || {};
const body = resp.body !== undefined ? resp.body : resp;
const rows = Array.isArray(body) ? body : [];

let results = 0, inserted = 0, duplicates = 0, errors = 0;
for (const r of rows) {
  results   += Number(r.results_found       || 0);
  inserted  += Number(r.new_leads_inserted  || 0);
  duplicates += Number(r.duplicates_skipped || 0);
  errors    += Number(r.errors              || 0);
}

const summary = {
  workflow: 'CLX-B2C-Discovery',
  run_completed_at: new Date().toISOString(),
  scan_log_rows: rows.length,
  totals: {
    results_found: results,
    new_leads_inserted: inserted,
    duplicates_skipped: duplicates,
    errors: errors
  },
  message: '[CLX B2C v2] Daily scan complete — ' + inserted + ' new leads, ' + duplicates + ' duplicates, ' + errors + ' errors across ' + rows.length + ' logged batches.'
};

console.log(summary.message);
return { json: summary };
